// 读取文档所有段落文本和编号信息
var doc = Application.ActiveDocument;
var sections = doc.Sections;
var result = [];

for (var i = 0; i < sections.Count; i++) {
    var section = sections.Item(i);
    var paragraphs = section.Paragraphs;

    for (var j = 1; j <= paragraphs.Count; j++) {
        var para = paragraphs.Item(j);
        var text = para.Range.Text;
        var hasNumbering = para.Range.ListFormat.ListType !== undefined && para.Range.ListFormat.ListType > 0;

        if (text.trim() && (text.length < 200)) {
            result.push({
                index: i + 1,
                paraIndex: j,
                text: text.replace(/\r\n|\n|\r/g, ''),
                hasNumbering: hasNumbering
            });
        }
    }
}

return result.slice(0, 50);

// 读取文档所有段落文本和编号信息（修正API调用）
var doc = Application.ActiveDocument;
var result = [];

if (!doc || !doc.Content) {
    return { error: "无法访问文档内容" };
}

var paragraphs = doc.Content.Paragraphs;

for (var j = 1; j <= paragraphs.Count && j <= 100; j++) {
    var para = paragraphs.Item(j);
    var text = para.Range.Text;

    // 检查是否有编号
    var hasNumbering = false;
    try {
        if (para.Range.ListFormat && para.Range.ListFormat.ListType !== undefined) {
            hasNumbering = para.Range.ListFormat.ListType > 0;
        }
    } catch(e) {}

    if (text.trim() && text.length < 200) {
        result.push({
            paraIndex: j,
            text: text.replace(/\r\n|\n|\r/g, ''),
            hasNumbering: hasNumbering
        });
    }
}

return result;

